var (
	UniswapV2PairABI       abi.ABI
	UniswapV2RouterAddress string
)

func InitUniswapV2EventFilter(_uniswapV2ContractAddress string) {

	var err error
	UniswapV2PairABI, err = abi.JSON(strings.NewReader(jsonStrUniswapV2PairABI))
	if err != nil {
		logrus.Fatalf("abi.Json error:%v", err)
		os.Exit(0)
	}

	UniswapV2RouterAddress = _uniswapV2ContractAddress
}

func FilterUniswapV2Event(txHash string, toAddr string, eventLog *eth_types.Log, contractAddr string, height uint64, topic0, topic1, topic2, topic3 string, topicCount int) interface{} {
	if event := filterSwap(txHash, toAddr, eventLog, contractAddr, height, topic0, topic1, topic2, topic3, topicCount); event != nil {
		return event
	}

	return nil
}

func filterSwap(txHash string, toAddr string, eventLog *eth_types.Log, contractAddr string, height uint64, topic0, topic1, topic2, topic3 string, topicCount int) *data.UniswapV2Swap {
	eventName := "Swap"

	if toAddr != UniswapV2RouterAddress {
		return nil
	}

	if !(topic0 == UniswapV2PairABI.Events[eventName].ID.Hex() && topicCount == 3) {
		return nil
	}

	sender := strings.ToLower(common.HexToAddress(topic1).Hex())
	to := strings.ToLower(common.HexToAddress(topic2).Hex())

	var eventNonIndexedData struct {
		Amount0In  *big.Int
		Amount1In  *big.Int
		Amount0Out *big.Int
		Amount1Out *big.Int
	}

	if err := UniswapV2PairABI.UnpackIntoInterface(&eventNonIndexedData, eventName, []byte(eventLog.Data)); err != nil {
		logrus.Fatalf("uniswapv2 UnpackIntoInterface err:%v height:%v", err, height)
		os.Exit(0)
	}

	event := &data.UniswapV2Swap{
		Pair:       strings.ToLower(contractAddr),
		Sender:     sender,
		Amount0In:  eventNonIndexedData.Amount0In.String(),
		Amount1In:  eventNonIndexedData.Amount1In.String(),
		Amount0Out: eventNonIndexedData.Amount0Out.String(),
		Amount1Out: eventNonIndexedData.Amount1Out.String(),
		To:         to,
	}

	return event
}
